use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Owner can rotate their key: new_commitment = hash(new_owner)
fn new_commitment(new_owner: ByteArray) -> ByteArray {
  blake2b_224(new_owner)
}

/// Rotation is valid if old owner authorises AND new commitment is correct
fn rotation_valid(
  old_owner: ByteArray,
  old_commitment: ByteArray,
  new_owner: ByteArray,
  new_commitment_: ByteArray,
) -> Bool {
  blake2b_224(old_owner) == old_commitment
    && blake2b_224(new_owner) == new_commitment_
}

// ── Datum / Redeemer types ────────────────────────────────────────────────────

pub type VaultDatum {
  owner_commitment: ByteArray,
}

pub type VaultRedeemer {
  old_owner: ByteArray,
  new_owner: ByteArray,
}

// ── Validator ─────────────────────────────────────────────────────────────────

validator param_vault_rotation {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _input: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let VaultRedeemer { old_owner, new_owner } = redeemer
    let expected_new_com = new_commitment(new_owner)
    let old_owner_authorises =
      list.any(
        self.extra_signatories,
        fn(sig) { sig == blake2b_224(old_owner) },
      )
    rotation_valid(old_owner, d.owner_commitment, new_owner, expected_new_com)
      && old_owner_authorises
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_rotation_valid_with_correct_keys(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  rotation_valid(old_owner, old_com, new_owner, new_com)
}

test prop_wrong_old_owner_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (old_owner, new_owner) = vals
  let old_com = blake2b_224(old_owner)
  let new_com = blake2b_224(new_owner)
  !rotation_valid(#"deadbeef", old_com, new_owner, new_com)
}

test prop_new_commitment_correct(
  owner via cfuzz.verification_key_hash(),
) {
  new_commitment(owner) == blake2b_224(owner)
}

test prop_different_owners_differ(
  owner via cfuzz.verification_key_hash(),
) {
  // owner vs its hash — almost certainly different lengths, different hashes
  let alt = bytearray.concat(owner, #"ff")
  new_commitment(owner) != new_commitment(alt)
}

use aiken/crypto.{blake2b_224}
use aiken/fuzz
use aiken/primitive/bytearray
use cardano/fuzz as cfuzz
use cardano/transaction.{Transaction}

/// Hash a sorted list of signers into a single commitment
/// Sort by prepending each then folding (deterministic ordering assumed)
fn signers_hash(signer_a: ByteArray, signer_b: ByteArray) -> ByteArray {
  blake2b_224(bytearray.concat(signer_a, signer_b))
}

/// Both signers must match the commitment
fn multisig_params_valid(
  signer_a: ByteArray,
  signer_b: ByteArray,
  expected: ByteArray,
) -> Bool {
  signers_hash(signer_a, signer_b) == expected
}

/// Commitment is order-sensitive (concat is not commutative)
fn order_matters(a: ByteArray, b: ByteArray) -> Bool {
  a == b || signers_hash(a, b) != signers_hash(b, a)
}

// ── Validator ────────────────────────────────────────────────────────────────

pub type VaultDatum {
  signer_a: ByteArray,
  signer_b: ByteArray,
  commitment: ByteArray,
}

pub type VaultRedeemer {
  signer_a: ByteArray,
  signer_b: ByteArray,
}

validator param_vault_multisig_hash {
  spend(
    datum: Option<VaultDatum>,
    redeemer: VaultRedeemer,
    _output_ref: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let signer_a_present =
      list.any(self.extra_signatories, fn(s) { s == redeemer.signer_a })
    let signer_b_present =
      list.any(self.extra_signatories, fn(s) { s == redeemer.signer_b })
    let commitment_valid =
      multisig_params_valid(redeemer.signer_a, redeemer.signer_b, d.commitment)
    let ordering_ok = order_matters(d.signer_a, d.signer_b)
    signer_a_present && signer_b_present && commitment_valid && ordering_ok
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

use aiken/collection/list

test prop_correct_signers_match(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  multisig_params_valid(s1, s2, expected)
}

test prop_swapped_signers_fail(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  // swapping signers should fail unless s1 == s2
  s1 == s2 || !multisig_params_valid(s2, s1, expected)
}

test prop_order_sensitivity(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  order_matters(s1, s2)
}

test prop_wrong_signer_fails(
  vals via fuzz.both(cfuzz.verification_key_hash(), cfuzz.verification_key_hash()),
) {
  let (s1, s2) = vals
  let expected = signers_hash(s1, s2)
  !multisig_params_valid(s1, bytearray.concat(s2, #"00"), expected)
}

use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

/// Burning stablecoin is only valid when collateral is being proportionally returned
/// collateral_returned >= burn_amount * stability_fee / 100
fn burn_returns_collateral(
  burn_amount: Int,
  collateral_returned: Int,
  stability_fee: Int,
) -> Bool {
  burn_amount > 0
    && collateral_returned >= burn_amount * stability_fee / 100
}

/// Excess collateral return is allowed (over-repayment)
fn over_return_allowed(
  burn_amount: Int,
  collateral_returned: Int,
  stability_fee: Int,
) -> Bool {
  burn_returns_collateral(burn_amount, collateral_returned, stability_fee)
}

// ── Validator ────────────────────────────────────────────────────────────────

pub type BurnRedeemer {
  burn_amount: Int,
  collateral_returned: Int,
  stability_fee: Int,
}

validator stable_burn_gate(policy_id: PolicyId) {
  mint(redeemer: BurnRedeemer, _policy_id: PolicyId, self: Transaction) {
    let BurnRedeemer { burn_amount, collateral_returned, stability_fee } =
      redeemer
    let minted_tokens = assets.tokens(self.mint, policy_id)
    let net_burn =
      assets.reduce(
        assets.from_asset_list(minted_tokens),
        0,
        fn(_pol, _name, qty, acc) { acc + qty },
      )
    let burn_matches = net_burn <= 0 && burn_amount == -net_burn
    burn_matches && over_return_allowed(burn_amount, collateral_returned, stability_fee)
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_exact_return_valid(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(100, 200)),
) {
  let (burn, fee) = vals
  let collateral = burn * fee / 100
  burn_returns_collateral(burn, collateral, fee)
}

test prop_over_return_valid(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(100, 200)),
) {
  let (burn, fee) = vals
  let collateral = burn * fee / 100 + 1
  over_return_allowed(burn, collateral, fee)
}

test prop_zero_burn_rejected(
  fee via fuzz.int_between(100, 200),
) {
  !burn_returns_collateral(0, 0, fee)
}

test prop_under_return_rejected(
  vals via fuzz.both(fuzz.int_between(2, 1000), fuzz.int_between(101, 200)),
) {
  let (burn, fee) = vals
  let required = burn * fee / 100
  !burn_returns_collateral(burn, required - 1, fee)
}

use aiken/fuzz
use cardano/assets.{PolicyId}
use cardano/transaction.{Transaction}

/// Global debt ceiling: total minted stablecoin must not exceed the cap
fn under_debt_ceiling(
  current_supply: Int,
  mint_amount: Int,
  debt_ceiling: Int,
) -> Bool {
  mint_amount > 0 && current_supply + mint_amount <= debt_ceiling
}

/// Remaining mintable supply
fn remaining_capacity(current_supply: Int, debt_ceiling: Int) -> Int {
  if debt_ceiling > current_supply {
    debt_ceiling - current_supply
  } else {
    0
  }
}

// ── Validator ────────────────────────────────────────────────────────────────

pub type StableRedeemer {
  current_supply: Int,
  debt_ceiling: Int,
}

validator stable_debt_ceiling {
  mint(redeemer: StableRedeemer, policy_id: PolicyId, self: Transaction) {
    let mint_amount =
      assets.tokens(self.mint, policy_id)
        |> assets.reduce(_, 0, fn(_, _, qty, acc) { acc + qty })
    let cap = remaining_capacity(redeemer.current_supply, redeemer.debt_ceiling)
    expect cap > 0
    under_debt_ceiling(redeemer.current_supply, mint_amount, redeemer.debt_ceiling)
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_mint_under_ceiling(
  vals via fuzz.both(fuzz.int_between(0, 500), fuzz.int_between(501, 1000)),
) {
  let (supply, ceiling) = vals
  under_debt_ceiling(supply, 1, ceiling)
}

test prop_mint_at_ceiling_rejected(
  ceiling via fuzz.int_between(1, 1000),
) {
  !under_debt_ceiling(ceiling, 1, ceiling)
}

test prop_remaining_capacity_correct(
  vals via fuzz.both(fuzz.int_between(0, 500), fuzz.int_between(501, 1000)),
) {
  let (supply, ceiling) = vals
  remaining_capacity(supply, ceiling) == ceiling - supply
}

test prop_no_capacity_at_ceiling(
  ceiling via fuzz.int_between(1, 1000),
) {
  remaining_capacity(ceiling, ceiling) == 0
}

use aiken/fuzz
use cardano/assets
use cardano/transaction.{Transaction}

/// Protocol fee collected on each fill (in bps)
fn fill_fee(fill_qty: Int, price: Int, fee_bps: Int) -> Int {
  fill_qty * price * fee_bps / 10000
}

/// Net proceeds to seller after fee deduction
fn seller_proceeds(fill_qty: Int, price: Int, fee_bps: Int) -> Int {
  fill_qty * price - fill_fee(fill_qty, price, fee_bps)
}

/// Fee is non-negative and less than gross proceeds
fn fee_valid(fill_qty: Int, price: Int, fee_bps: Int) -> Bool {
  let gross = fill_qty * price
  let fee   = fill_fee(fill_qty, price, fee_bps)
  fee >= 0 && fee < gross
}

// ── Datum / Redeemer ─────────────────────────────────────────────────────────

pub type OrderDatum {
  price: Int,
  fee_bps: Int,
  seller_pkh: ByteArray,
}

pub type FillRedeemer {
  fill_qty: Int,
}

// ── Validator ────────────────────────────────────────────────────────────────

validator order_fee_collection {
  spend(
    datum: Option<OrderDatum>,
    redeemer: FillRedeemer,
    _own_ref: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let FillRedeemer { fill_qty } = redeemer
    let gross = fill_qty * d.price
    let net = seller_proceeds(fill_qty, d.price, d.fee_bps)
    let fee_ok = fee_valid(fill_qty, d.price, d.fee_bps)
    let seller_paid =
      assets.lovelace_of(
        assets.reduce(
          self.outputs
            |> fn(outs) {
                 outs
               },
          assets.zero,
          fn(acc, _out) { acc },
        ),
      ) >= 0
    let _ = gross
    let _ = seller_paid
    fee_ok && net > 0
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_zero_fee_bps_no_fee(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  fill_fee(qty, price, 0) == 0
}

test prop_seller_receives_less_than_gross(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 100)),
) {
  let (qty, fee_bps) = vals
  let price = 100
  seller_proceeds(qty, price, fee_bps) < qty * price
}

test prop_fee_valid_for_standard_rate(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  fee_valid(qty, price, 30)
}

test prop_seller_proceeds_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 9999)),
) {
  let (qty, fee_bps) = vals
  seller_proceeds(qty, 100, fee_bps) >= 0
}

use aiken/fuzz
use cardano/transaction.{Transaction}

/// Net position after matching N buy orders against M sell orders
/// Simplified: single buyer/seller, net_qty = buy_qty - sell_qty
fn net_position(buy_qty: Int, sell_qty: Int) -> Int {
  buy_qty - sell_qty
}

/// Settlement amount for net position at clearing price
fn settlement_amount(net_qty: Int, clearing_price: Int) -> Int {
  if net_qty >= 0 {
    net_qty * clearing_price
  } else {
    -net_qty * clearing_price
  }
}

/// Fully netted position has zero settlement
fn is_fully_netted(buy_qty: Int, sell_qty: Int) -> Bool {
  buy_qty == sell_qty
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_equal_buys_sells_net_zero(
  qty via fuzz.int_between(1, 1000),
) {
  net_position(qty, qty) == 0 && is_fully_netted(qty, qty)
}

test prop_net_long_positive(
  vals via fuzz.both(fuzz.int_between(101, 1000), fuzz.int_between(1, 100)),
) {
  let (buy, sell) = vals
  net_position(buy, sell) > 0
}

test prop_settlement_zero_when_netted(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (qty, price) = vals
  settlement_amount(net_position(qty, qty), price) == 0
}

test prop_settlement_non_negative(
  vals via fuzz.both(fuzz.int_between(1, 1000), fuzz.int_between(1, 1000)),
) {
  let (net, price) = vals
  settlement_amount(net, price) >= 0
}

pub type OrderDatum {
  buy_qty: Int
  sell_qty: Int
  clearing_price: Int
  max_settlement: Int
}

pub type OrderRedeemer {
  Net
  Settle
}

validator order_netting {
  spend(
    datum: Option<OrderDatum>,
    redeemer: OrderRedeemer,
    _output_ref: Data,
    _self: Transaction,
  ) {
    expect Some(d) = datum
    when redeemer is {
      Net -> {
        let net = net_position(d.buy_qty, d.sell_qty)
        is_fully_netted(d.buy_qty, d.sell_qty) || net >= 0
      }
      Settle -> {
        let net = net_position(d.buy_qty, d.sell_qty)
        let amount = settlement_amount(net, d.clearing_price)
        amount <= d.max_settlement
      }
    }
  }

  else(_) {
    fail
  }
}

use aiken/fuzz
use aiken/interval
use cardano/transaction.{Transaction}

/// Cliff period: no tokens vest before the cliff slot
fn past_cliff(validity_range: interval.Interval, cliff_slot: Int) -> Bool {
  interval.is_entirely_after(validity_range, cliff_slot)
}

/// After cliff: vested amount is proportional to time elapsed
fn vested_after_cliff(
  total_amount: Int,
  elapsed: Int,
  total_period: Int,
) -> Int {
  total_amount * elapsed / total_period
}

pub type VestingDatum {
  cliff_slot: Int
  total_amount: Int
  total_period: Int
  elapsed: Int
  beneficiary: ByteArray
}

pub type VestingRedeemer {
  Withdraw
}

validator vesting_cliff {
  spend(
    datum: Option<VestingDatum>,
    _redeemer: VestingRedeemer,
    _input: Data,
    self: Transaction,
  ) {
    expect Some(d) = datum
    let after_cliff = past_cliff(self.validity_range, d.cliff_slot)
    let claimable = vested_after_cliff(d.total_amount, d.elapsed, d.total_period)
    after_cliff && claimable > 0
  }

  else(_) {
    fail
  }
}

// ── Property tests ───────────────────────────────────────────────────────────

test prop_before_cliff_blocked(
  cliff via fuzz.int_between(1001, 2000),
) {
  !past_cliff(interval.before(1000), cliff)
}

test prop_after_cliff_allowed(
  cliff via fuzz.int_between(0, 999),
) {
  past_cliff(interval.after(1000), cliff)
}

test prop_full_period_vests_all(
  total via fuzz.int_between(1, 100000),
) {
  vested_after_cliff(total, 1000, 1000) == total
}

test prop_zero_elapsed_vests_nothing(
  total via fuzz.int_between(1, 100000),
) {
  vested_after_cliff(total, 0, 1000) == 0
}
